const metrics = $input.all();
const totalRevenue = metrics.reduce((sum, m) => sum + (m.total_revenue || 0), 0);
const totalEvents = metrics.reduce((sum, m) => sum + (m.total_events || 0), 0);
const avgRevenue = totalRevenue / metrics.length;
return { totalRevenue, totalEvents, avgRevenue, metricsCount: metrics.length };

